let results = [];

for (const item of $input.all()) {
  for (const key of Object.keys(item.binary)) {
    const binaryData = item.binary[key];

    results.push({
      json: {
        fileKey: key,
        fileName: binaryData.fileName || null,
        mimeType: binaryData.mimeType || null,
      },
      binary: {
        [key]: binaryData, // keep binary for Extract from File
      },
    });
  }
}

return results;

