for (const item of $input.all()) {
  let raw = item.json.text ? item.json.text : item.json.data;

  const clean = raw
    .replace(/[ \t]+/g, " ") // collapse spaces & tabs
    .replace(/\n\s*\n+/g, "\n") // collapse multiple newlines
    .replace(/[,]+/g, ",") // clean up extra commas
    .trim();

  const preview = clean.toLowerCase().substring(0, 3000);
    // Escape for JSON
  const escapedPreview = preview
    .replace(/\\/g, "\\\\")  // escape backslashes
    .replace(/"/g, '\\"')    // escape quotes
    .replace(/\n/g, " ");  // escape newlines
  item.json.preview = escapedPreview;
  item.json.text = clean;
  item.json.document_hint = {};
}

return $input.all();

